        // connect to the backend origin and send the request
        let conn = match tls_settings {
            Some(builder) => TcpStream::connect_with_tls(builder),
            None => TcpStream::connect((backend.host, backend.port)),
        };
        conn.write(req.to_string()).unwrap();

        // read the response from the backend origin and return it to the client
